  '{"scenarios": [{"label": "compliance", "probability": 0.02}, {"label": "escalation", "probability": 0.60}, {"label": "status_quo", "probability": 0.35}, {"label": "negotiation", "probability": 0.03}], "gdp_impact_pct": -5.0}',
